DEV ortamda Rita DB’de aşağıdaki query’nin çalıştırılması gerekmektedir:
ALTER TABLE rita_definition.progressive_tier ADD COLUMN commission_item_id BIGINT;
ALTER TABLE rita_definition.progressive_tier ADD CONSTRAINT fk_progressive_tier_commission_item 
    FOREIGN KEY (commission_item_id) REFERENCES rita_definition.commission_item(id);

UPDATE rita_definition.progressive_tier pt
SET commission_item_id = (
    SELECT ci.id FROM rita_definition.commission_item ci
    WHERE ci.version_id = pt.version_id
    ORDER BY ci.id ASC LIMIT 1
)
WHERE pt.commission_item_id IS NULL;

ALTER TABLE rita_definition.progressive_tier DROP COLUMN version_id;

ALTER TABLE rita_definition.progressive_tier ALTER COLUMN commission_item_id SET NOT NULL;

